import { call, put, takeLatest } from 'redux-saga/effects';
import axios from 'axios';
import {
  loginRequest,
  loginSuccess,
  loginFailure,
  registerRequest,
  registerSuccess,
  registerFailure,
} from '../slices/authSlice';
import { mergeCartRequest } from '../slices/cartSlice';
import { API_URL, getSessionId } from '../../utils/api';

function* loginSaga(action) {
  try {
    const { phone, password, navigate } = action.payload;
    const response = yield call(axios.post, `${API_URL}/api/ecommerce/auth/login`, {
      phone,
      password,
    });
    yield put(loginSuccess(response.data));

    // Merge guest cart with customer cart
    const sessionId = getSessionId();
    yield put(mergeCartRequest({ sessionId }));

    if (navigate) {
      navigate('/');
    }
  } catch (error) {
    yield put(loginFailure(error.response?.data?.message || 'Login failed'));
  }
}

function* registerSaga(action) {
  try {
    const { navigate, ...customerData } = action.payload;
    const response = yield call(axios.post, `${API_URL}/api/ecommerce/auth/register`, customerData);
    yield put(registerSuccess(response.data));

    // Merge guest cart with customer cart
    const sessionId = getSessionId();
    yield put(mergeCartRequest({ sessionId }));

    if (navigate) {
      navigate('/');
    }
  } catch (error) {
    yield put(registerFailure(error.response?.data?.message || 'Registration failed'));
  }
}

export default function* authSaga() {
  yield takeLatest(loginRequest.type, loginSaga);
  yield takeLatest(registerRequest.type, registerSaga);
}
